// // This module implements a 5-bit Johnson counter with a clock input and a reset input. On each clock edge, the counter shifts its state to the right and the inverted output of the first flip-flop should enter the last flip-flop. The counter should be reset to 1 when the reset signal is asserted.
module johnson_counter(
    input wire clk,
    input wire reset,
    output reg [4:0] Q
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 5'b00000;
        end else begin
            Q <= {Q[3:0], ~Q[4]};
        end
    end
endmodule
